<template>
  <div class="istadetail">
    <main>
      <div class="title">
        <h1>委托单编号:{{ detail.entrustCode }}</h1>
        <h6>订单状态:<van-tag plain type="success">历史订单</van-tag></h6>
        <h6>下单时间:{{ detail.entrustTime }}</h6>

        <div class="button">
          <van-button
            round
            type="info"
            size="small"
            @click="detailista(detail.entrustCode)"
            >委托详情</van-button
          >
          <van-button
            round
            type="primary"
            size="small"
            @click="once(detail.entrustCode)"
            >再来一单</van-button
          >
          <!-- <van-button round size="small"
           @click="downloadcheck" >下载报告</van-button
          > -->
        </div>
      </div>
    </main>
  </div>
</template>

<script>
import { getistas } from "../utils/http/api";
import { once } from "../utils/once";
import { mapMutations } from "vuex";
export default {
  props: ["detail"],
  methods: {
    ...mapMutations(["setsampleList", "setentrustInfo", "deltotalsampleList"]),
     downloadcheck() {
      this.$router.push({
        name: "loadcheck",
        query: { sampleId: this.checkid, entrustId: this.detail.entrustCode },
      });
    },
    detailista(entrustId) {
      this.$router.push({
        name: "Istaproductdetail",
        query: { entrustId },
      });
    },
    once(entrustCode) {
      

      this.deltotalsampleList();

      getistas(entrustCode).then((res) => {
        console.log(res);
        if (res.data.code === 200) {
          let data = once(res.data.data);
          // 设置检测列表
          data.sampleList.forEach((item) => {
            this.setsampleList(item);
          });
          // 设置检测项
          this.setentrustInfo(data.entrustInfo);

          this.$router.push({ name: "ista" });
        }
      });
    },
  },
};
</script>


<style lang="less">
.istadetail {
  width: 7.5rem;
  // height: 150px;
  padding: 0.2rem 0.4rem;

  box-sizing: border-box;
  // background: khaki;
  main {
    width: 100%;
    height: 100%;
    border-radius: 0.2rem;
    background: white;
    overflow: hidden;
    display: flex;
    flex-direction: column;

    .title {
      display: flex;
      flex-direction: column;
      margin: 0.2rem 0.2rem 0px 0.2rem;
      padding: 0.2rem 0.2rem 0px 0.2rem;
      box-sizing: border-box;
    }
    h1 {
      font-size: 0.32rem;
      font-weight: 600;
      // margin-top:5px;
    }
    h6 {
      font-size: 0.24rem;
      font-weight: 400;
      margin-top: 0.1rem;
    }
    p {
      font-size: 0.24rem;
      margin-top: 0.1rem;
      margin-bottom: 0.1rem;
    }
  }
  .button {
    display: flex;
    margin-top: 20px;
    justify-content: space-around;
    align-items: center;
    padding-bottom: 10px;
  }
}
</style>