<template>
  <div class="myista">
    <van-sticky>
      <van-nav-bar
        title="我的委托"
        left-arrow
        @click-left="onClickLeft"
        @click-right="onClickRight"
      />
    </van-sticky>
    <Timeselect @gettime="time" />
    <div class="button_time">
      <el-button size="mini" round @click="atime(1)">近一周</el-button>
      <el-button size="mini" round @click="atime(2)">近一月</el-button>
      <el-button size="mini" round @click="atime(3)">近三个月</el-button>
      <el-button size="mini" round @click="atime(4)">近半年</el-button>
    </div>
    <div class="sorll">
      <ul>
        <template v-if="type === '0'">
          <li v-for="(item, i) in list" :key="i">
            <Istacard :detail="item" :active="1" />
          </li>
        </template>

        <template v-if="type === '2'">
          <li v-for="(item, i) in list" :key="i">
            <Historyista :detail="item" :active="1" />
          </li>
        </template>
      </ul>

      <div class="isloading">
        <span
          ><i v-if="loadingtext === '加载中...'" class="el-icon-loading"></i
          >{{ loadingtext }}
        </span>
      </div>
    </div>
    <el-empty
      v-if="list.length === 0"
      :image-size="200"
      style="height: 100%; background: #fff"
    ></el-empty>
  </div>
</template>
<script>
import Istacard from "../../components/Istacard.vue";
import Timeselect from "../../components/time/Timeselect.vue";
import Historyista from "../../components/historyista.vue";
import { getuserlist } from "../../utils/http/api.js";
import { mapState } from "vuex";

export default {
  name: "myista",
  components: {
    Istacard,
    Timeselect,
    Historyista,
  },
  data() {
    return {
      type: "0",
      start_time: "",
      end_time: "",
      pageNo: 1,
      pageSize: 5,
      endScreen: false,
      isloading: false,
      list: [],
      loadingtext: "",
      activeTime: 1,
    };
  },
  computed: {
    ...mapState(["userid", "adminId"]),
  },
  watch: {
    endScreen: function (newval, old) {
      // console.log(newval);
      if (newval) {
        // get
        this.isloading = true;
        this.loadingtext = "加载中...";
        this.pageNo++;
        let info = {
          type: this.type,
          userId: this.userid * 1,
          adminId: this.adminId,
          startTime: this.start_time,
          endTime: this.end_time,
          pageNo: this.pageNo,
          pageSize: this.pageSize,
        };
        setTimeout(() => {
          this.getdataScroll(info).then(
            (res) => {
              console.log("页数", this.pageNo, res);
              // this.list.forEach((element) => {
              //   this.list.push("1");
              // });
              let len = res.data.data.list.length;
              if (len > 0) {
                res.data.data.list.map((item) => {
                  this.list.push(item);
                });
                this.loadingtext = "";
              } else if (len === 0) {
                this.pageNo--;
                if (this.list.length === 0) {
                  this.loadingtext = "";
                } else {
                  this.loadingtext = "到底了！";
                }
              }

              this.isloading = false;
            },
            (err) => {
              this.pageNo = 1;
              this.isloading = false;
              this.isloadingtext = "网络错误！";
            }
          );
        }, 0);
      }
    },
  },

  activated() {
    // 不传type 所有
    // this.type = this.$route.query.type;
    let the = this;
    window.addEventListener("scroll", the.scrollFunc, false);
  },
  deactivated() { 
    this.clearScroll();
  },
  created() {
    // 近一周
    this.atime(1);
  },
  methods: {
    getdata() {
      this.pageNo = 1;
      this.list = [];

      let info = {
        type: this.type,
        userId: this.userid * 1,
        adminId: this.adminId,
        startTime: this.start_time,
        endTime: this.end_time,
        pageNo: this.pageNo,
        pageSize: this.pageSize,
      };
      getuserlist(info).then((res) => {
        console.log(res);
        res.data.data.list.map((item) => {
          this.list.push(item);
        });
      });
    },
    getdataScroll(info) {
      return getuserlist(info);
    },
    atime(index) {
      let date = new Date();

      switch (index) {
        case 1:
          this.end_time = date.getTime(date);
          this.start_time = new Date(date - 3600 * 24 * 7 * 1000).getTime();
          this.getdata();

          break;
        case 2:
          this.end_time = date.getTime(date);
          this.start_time = new Date(date - 3600 * 24 * 30 * 1000).getTime();
          this.getdata();

          break;
        case 3:
          this.end_time = date.getTime(date);
          this.start_time = new Date(date - 3600 * 24 * 90 * 1000).getTime();
          this.getdata();

          break;
        case 4:
          this.end_time = date.getTime(date);
          this.start_time = new Date(date - 3600 * 24 * 180 * 1000).getTime();
          this.getdata();

          break;

        default:
          // 近一周
          this.end_time = date.getTime(date);
          this.start_time = new Date(date - 3600 * 24 * 7 * 1000).getTime();
          this.getdata();

          break;
      }
    },
    time(start, end) {
      this.start_time = start.getTime(start);
      this.end_time = end.getTime(end);

      this.getdata();
    },
    scrollFunc() {
      this.endScreen = this.screenCheck();
    },
    // 检测屏幕是否到达底部的方法
    screenCheck() {
      if (this.isloading) return false;
      let screenH = Math.ceil(window.innerHeight + window.scrollY); // 屏幕高度+滚动高度
      let eleH = document.documentElement.scrollHeight; // 网页正文全文高
      // console.log(screenH, eleH);
      return screenH === eleH;
    },
    clearScroll() {
      let the = this;
      window.removeEventListener("scroll", the.scrollFunc, false);
    },
    onClickLeft() {
      this.$router.go(-1);
    },
    onClickRight() {},
  },
};
</script>

<style lang="less">
.myista {
  width: 7.5rem;
  height: 100vh;
  background: @gray-2;
  .button_time {
    position: fixed;
    display: flex;
    justify-content: space-around;
    width: 100%;
    top: 90px;
    background: white;
    z-index: 100;
    padding: 5px;
    box-sizing: border-box;
  }
  .sorll {
    background: @gray-2;
    margin-top: 90px;
    overflow-y: scroll;
  }
  .isloading {
    height: 30px;
    display: flex;
    justify-content: center;
    align-items: center;
    span {
      font-size: 16px;
      font-weight: 500;
    }
  }
}
</style>